namespace NotificationsApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly string[] _templates =
    [
        "New comment on your post",
        "Your build succeeded",
        "Deployment to production completed",
        "Pull request approved",
        "New follower added",
        "Security alert resolved",
        "Scheduled maintenance upcoming",
        "Your report is ready"
    ];

    /// <summary>
    /// Returns an initial set of notifications (used during SSR).
    /// </summary>
    public List<NotificationItem> GetInitialNotifications()
    {
        return Enumerable.Range(0, 5).Select(_ => GenerateNotification()).ToList();
    }

    /// <summary>
    /// Simulates checking for new notifications. Returns 0-2 new items randomly.
    /// </summary>
    public List<NotificationItem> CheckForNewNotifications()
    {
        var count = Random.Shared.Next(0, 3);
        return Enumerable.Range(0, count).Select(_ => GenerateNotification()).ToList();
    }

    private NotificationItem GenerateNotification()
    {
        return new NotificationItem
        {
            Id = _nextId++,
            Message = _templates[Random.Shared.Next(_templates.Length)],
            Timestamp = DateTime.Now
        };
    }
}

