+@page "/notifications"
+@rendermode InteractiveServer
+@implements IDisposable
+@inject NotificationsApp.Services.NotificationService NotificationService
+
+<PageTitle>Notifications</PageTitle>
+
+<h1>Notifications <span class="badge bg-primary">@_notifications.Count</span></h1>
+
+@if (_notifications.Count == 0)
+{
+    <p><em>No notifications.</em></p>
+}
+else
+{
+    <ul class="list-group">
+        @foreach (var item in _notifications.OrderByDescending(n => n.Timestamp))
+        {
+            <li class="list-group-item d-flex justify-content-between align-items-center">
+                <span>@item.Message</span>
+                <small class="text-muted">@item.Timestamp.ToString("HH:mm:ss")</small>
+            </li>
+        }
+    </ul>
+}
+
+@code {
+    private List<NotificationsApp.Services.NotificationItem> _notifications = new();
+    private CancellationTokenSource? _cts;
+
+    // OnInitialized runs during both SSR and interactive — load initial data here.
+    protected override void OnInitialized()
+    {
+        _notifications = NotificationService.GetInitialNotifications();
+    }
+
+    // OnAfterRenderAsync with firstRender==true only fires when the component is
+    // live and interactive in the browser — never during static SSR.
+    protected override async Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (firstRender)
+        {
+            _cts = new CancellationTokenSource();
+            _ = PollForNotificationsAsync(_cts.Token);
+        }
+    }
+
+    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
+    {
+        while (!cancellationToken.IsCancellationRequested)
+        {
+            try
+            {
+                await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);
+
+                var newItems = NotificationService.CheckForNewNotifications();
+                if (newItems.Count > 0)
+                {
+                    _notifications.AddRange(newItems);
+                    await InvokeAsync(StateHasChanged);
+                }
+            }
+            catch (TaskCanceledException)
+            {
+                break;
+            }
+        }
+    }
+
+    public void Dispose()
+    {
+        _cts?.Cancel();
+        _cts?.Dispose();
+    }
+}
